package com.hospital.management.util;import org.junit.jupiter.api.*;import java.math.*;import java.time.*;import static org.junit.jupiter.api.Assertions.*;class AdmissionChargeCalculatorTest{AdmissionChargeCalculator c=new AdmissionChargeCalculator();LocalDateTime a=LocalDateTime.of(2026,7,22,10,0);@Test void partialDaysRoundUp(){assertEquals(1,c.calculateChargeableDays(a,a.plusHours(8)));assertEquals(1,c.calculateChargeableDays(a,a.plusHours(23)));assertEquals(2,c.calculateChargeableDays(a,a.plusHours(25)));}@Test void calculatesDecimalCharge(){assertEquals(new BigDecimal("3000.00"),c.calculateRoomCharge(a,a.plusHours(25),new BigDecimal("1500")));}@Test void rejectsReverseDates(){assertThrows(IllegalArgumentException.class,()->c.calculateChargeableDays(a,a.minusMinutes(1)));}}
